input.command:
pkill waybar
# GTK3 `color` in a parent does NOT cascade to child label nodes unless
# the label node itself is targeted. Let's check what other working waybar configs do.
# The real fix: put `color` directly on `label` with no parent selector.
# Test this by stripping it down completely.
cat > /tmp/test-waybar.css << 'EOF'
* {
    font-family: monospace;
    font-size: 13px;
}
label {
    color: #ff0000;
}
window#waybar {
    background-color: #121318;
}
EOF
GTK_THEME=Adwaita:dark waybar --style /tmp/test-waybar.css &>/tmp/waybar.log &
sleep 2
echo "running"

