window#waybar {
    background-color: rgba(18, 19, 24, 0.75);
    color: #ffffff;
    border-bottom: 1px solid rgba(69, 70, 79, 0.3);
}

/* ── Workspaces ─────────────────────────────────────────── */

#workspaces {
    margin: 4px 8px;
    padding: 0;
}

#workspaces button {
    padding: 0 10px;
    margin: 0 2px;
    background-color: rgba(30, 31, 37, 0.7);
    color: #ffffff;
    border-radius: 8px;
    min-width: 28px;
    min-height: 28px;
    transition: all 0.15s ease;
}

#workspaces button:hover {
    background-color: rgba(40, 42, 47, 0.9);
    color: #ffffff;
}

#workspaces button.active {
    background-color: #ffffff;
    color: #172e60;
    font-weight: bold;
}

#workspaces button.urgent {
    background-color: #ffb4ab;
    color: #690005;
}

/* ── Window title ───────────────────────────────────────── */

#window {
    padding: 0 12px;
    color: #ffffff;
    font-style: italic;
}

/* ── Shared module pill style ───────────────────────────── */

#cpu,
#memory,
#temperature,
#network,
#pulseaudio,
#clock,
#tray {
    padding: 0 12px;
    margin: 4px 2px;
    background-color: rgba(30, 31, 37, 0.7);
    color: #ffffff;
    border-radius: 8px;
    min-height: 28px;
}

/* ── Per-module accents ─────────────────────────────────── */

#clock {
    color: #ffffff;
    font-weight: bold;
}

#cpu {
    color: #ffffff;
}

#memory {
    color: #ffffff;
}

#temperature {
    color: #ffffff;
}

#temperature.critical {
    background-color: rgba(147, 0, 10, 0.8);
    color: #ffdad6;
}

#network {
    color: #ffffff;
}

#network.disconnected {
    background-color: rgba(147, 0, 10, 0.5);
    color: #ffdad6;
}

#pulseaudio {
    color: #ffffff;
}

#pulseaudio.muted {
    color: #ffffff;
}

#tray {
    padding: 0 8px;
}

#tray > .passive {
    -gtk-icon-effect: dim;
}

#tray > .needs-attention {
    -gtk-icon-effect: highlight;
    background-color: rgba(255, 180, 171, 0.3);
}

