toolUseResult.originalFile:
// -*- mode: jsonc -*-
{
    "layer": "top",
    "position": "top",
    "height": 36,
    "spacing": 0,

    "modules-left": ["hyprland/workspaces"],
    "modules-center": ["hyprland/window"],
    "modules-right": ["cpu", "memory", "temperature", "network", "pulseaudio", "clock", "tray"],

    "hyprland/workspaces": {
        "format": "{name}",
        "on-click": "activate",
        "sort-by-number": true
    },

    "hyprland/window": {
        "max-length": 60,
        "separate-outputs": true
    },

    "cpu": {
        "interval": 2,
        "format": "🖥️ {usage}%",
        "tooltip": false
    },

    "memory": {
        "interval": 5,
        "format": "🧠 {percentage}%",
        "tooltip-format": "{used:0.1f}G / {total:0.1f}G"
    },

    "temperature": {
        "hwmon-path": "/sys/class/hwmon/hwmon4/temp1_input",
        "critical-threshold": 85,
        "format": "🌡️ {temperatureC}°C",
        "format-critical": "🔥 {temperatureC}°C"
    },

    "network": {
        "interface": "enp12s0",
        "format-ethernet": "🌐 {ipaddr}",
        "format-disconnected": "⚠️ No Network",
        "tooltip-format": "{ifname}: {ipaddr}/{cidr}\n↑ {bandwidthUpBits}  ↓ {bandwidthDownBits}"
    },

    "pulseaudio": {
        "format": "{icon} {volume}%",
        "format-muted": "🔇 Muted",
        "format-icons": {
            "default": ["🔈", "🔉", "🔊"]
        },
        "on-click": "pavucontrol",
        "tooltip-format": "{desc}"
    },

    "clock": {
        "format": "🕐 {:%H:%M}",
        "format-alt": "📅 {:%a, %d %b %Y}",
        "tooltip-format": "<big>{:%B %Y}</big>\n<tt><small>{calendar}</small></tt>"
    },

    "tray": {
        "spacing": 6,
        "icon-size": 16
    }
}

